import React, { useEffect, useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { supabase } from '../services/supabaseClient';
import { Plus, Search, Filter, Calendar, Tag, Edit3, Trash2, X, Save } from 'lucide-react';
import '../styles/Despesas.css';

const Despesas = () => {
  const [despesas, setDespesas] = useState([]);
  const [categorias, setCategorias] = useState([]);
  const [loading, setLoading] = useState(true);
  const [searchTerm, setSearchTerm] = useState('');
  
  // Modal State
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [itemEditando, setItemEditando] = useState(null);

  const navigate = useNavigate();

  useEffect(() => {
    buscarDados();
  }, []);

  async function buscarDados() {
    setLoading(true);
    try {
      const { data: dataDesp, error: errDesp } = await supabase
        .from('compras')
        .select(`*, categorias (nome, cor)`)
        .eq('tipo_despesa', 'Gastos Variáveis')
        .order('data_compra', { ascending: false });

      const { data: dataCat } = await supabase.from('categorias').select('*');

      if (errDesp) throw errDesp;
      setDespesas(dataDesp || []);
      setCategorias(dataCat || []);
    } catch (error) {
      console.error("Erro ao carregar:", error);
    } finally {
      setLoading(false);
    }
  }

  const handleAbrirModal = (item) => {
    setItemEditando({ ...item });
    setIsModalOpen(true);
  };

  const handleSalvarEdicao = async (e) => {
    e.preventDefault();
    try {
      const { error } = await supabase
        .from('compras')
        .update({
          descricao: itemEditando.descricao,
          valor_total: itemEditando.valor_total,
          data_compra: itemEditando.data_compra,
          categoria_id: itemEditando.categoria_id,
          forma_pagamento: itemEditando.forma_pagamento
        })
        .eq('id', itemEditando.id);

      if (error) throw error;
      setIsModalOpen(false);
      buscarDados();
    } catch (error) {
      alert("Erro ao salvar: " + error.message);
    }
  };

  const handleExcluir = async () => {
    if (window.confirm(`Excluir "${itemEditando.descricao}"?`)) {
      try {
        const { error } = await supabase
          .from('compras')
          .delete()
          .eq('id', itemEditando.id);
        
        if (error) throw error;
        setIsModalOpen(false);
        buscarDados();
      } catch (error) {
        alert("Erro ao excluir: " + error.message);
      }
    }
  };

  const formatarMoeda = (valor) => {
    return Number(valor).toLocaleString('pt-BR', { style: 'currency', currency: 'BRL' });
  };

  const filteredDespesas = despesas.filter(d => 
    d.descricao.toLowerCase().includes(searchTerm.toLowerCase())
  );

  return (
    <div className="desp-premium-wrapper fade-in">
      
      {/* Header e Resumo Grid */}
      <div className="desp-top-layout">
        <header className="desp-panel desp-header-area">
          <div className="desp-title-area">
            <h1>Despesas</h1>
            <p>Pagamentos à vista e variáveis</p>
          </div>
          
          <div className="desp-search-box">
            <Search size={18} className="text-slate-400" />
            <input 
              type="text" 
              placeholder="Pesquisar despesa..." 
              value={searchTerm}
              onChange={(e) => setSearchTerm(e.target.value)}
            />
          </div>
        </header>

        <div className="desp-panel desp-summary-card">
          <span className="summary-label">Total do Período</span>
          <h2 className="summary-value">
            {formatarMoeda(filteredDespesas.reduce((acc, curr) => acc + Number(curr.valor_total), 0))}
          </h2>
        </div>
      </div>

      {/* Listagem */}
      <main className="desp-panel desp-list-panel">
        <div className="list-header">
          <h3 style={{fontWeight: 800, color: '#475569'}}>Movimentações</h3>
          <Filter size={18} color="#94a3b8" />
        </div>

        <div className="desp-list">
          {loading ? (
            <div style={{padding: '40px', textAlign: 'center', color: '#64748b'}}>Carregando...</div>
          ) : filteredDespesas.map((item) => (
            <div key={item.id} className="desp-item-row" onClick={() => handleAbrirModal(item)}>
              <div className="desp-item-info">
                <div className="cat-indicator" style={{ backgroundColor: item.categorias?.cor || '#cbd5e1' }}></div>
                <div className="desp-details">
                  <span className="desp-desc">{item.descricao}</span>
                  <div className="desp-meta">
                    <span className="meta-tag"><Calendar size={12} /> {new Date(item.data_compra).toLocaleDateString('pt-BR')}</span>
                    <span className="meta-tag"><Tag size={12} /> {item.categorias?.nome}</span>
                    <span className="method-badge">{item.forma_pagamento}</span>
                  </div>
                </div>
              </div>
              <span className="desp-value">{formatarMoeda(item.valor_total)}</span>
            </div>
          ))}
        </div>
      </main>

      {/* Modal de Detalhes e Edição */}
      {isModalOpen && itemEditando && (
        <div className="modal-overlay" onClick={() => setIsModalOpen(false)}>
          <div className="edit-modal" onClick={e => e.stopPropagation()}>
            <div style={{display: 'flex', justifyContent: 'space-between', alignItems: 'center'}}>
              <h2 style={{margin: 0, fontWeight: 900, letterSpacing: '-1px'}}>Detalhes</h2>
              <button onClick={() => setIsModalOpen(false)} style={{background: '#f1f5f9', border: 'none', padding: '8px', borderRadius: '12px', cursor: 'pointer'}}>
                <X size={20} color="#64748b" />
              </button>
            </div>

            <form onSubmit={handleSalvarEdicao} className="edit-form-grid">
              <div className="form-group">
                <label>O QUE FOI COMPRADO?</label>
                <input 
                  type="text" 
                  value={itemEditando.descricao} 
                  onChange={e => setItemEditando({...itemEditando, descricao: e.target.value})}
                  placeholder="Ex: Mercado, Aluguel..."
                />
              </div>

              <div style={{display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '15px'}}>
                <div className="form-group">
                  <label>VALOR</label>
                  <input 
                    type="number" 
                    step="0.01"
                    value={itemEditando.valor_total} 
                    onChange={e => setItemEditando({...itemEditando, valor_total: e.target.value})}
                  />
                </div>
                <div className="form-group">
                  <label>DATA</label>
                  <input 
                    type="date" 
                    value={itemEditando.data_compra} 
                    onChange={e => setItemEditando({...itemEditando, data_compra: e.target.value})}
                  />
                </div>
              </div>

              <div className="form-group">
                <label>CATEGORIA</label>
                <select 
                  value={itemEditando.categoria_id} 
                  onChange={e => setItemEditando({...itemEditando, categoria_id: e.target.value})}
                >
                  {categorias.map(cat => (
                    <option key={cat.id} value={cat.id}>{cat.nome}</option>
                  ))}
                </select>
              </div>

              <div className="modal-footer-actions">
                <button type="submit" className="btn-save-full">
                  <Save size={18} /> Salvar Alterações
                </button>
                <button type="button" className="btn-delete-full" onClick={handleExcluir}>
                  <Trash2 size={18} /> Excluir Lançamento
                </button>
              </div>
            </form>
          </div>
        </div>
      )}

      {/* FAB Mobile/Desktop */}
      <button className="desp-fab" onClick={() => navigate('/lancamento')}>
        <Plus size={32} />
      </button>
    </div>
  );
};

export default Despesas;
